const release = $input.first().json.body.release;
const repo = $input.first().json.body.repository;

const tag = release.tag_name;
const title = release.name || tag;
let body = release.body || 'No release notes.';
if (body.length > 4000) body = body.substring(0, 4000) + '...';
const url = release.html_url;
const author = release.author ? release.author.login : 'unknown';
const publishedAt = release.published_at;

const discordPayload = {
  embeds: [{
    title: '\u{1F680} ' + title,
    url: url,
    color: 5763719,
    description: body,
    fields: [
      {
        name: '\u{1F4E6} Install',
        value: '```bash\nlean-ctx update\ncargo install lean-ctx\nnpm i -g lean-ctx-bin\nbrew upgrade lean-ctx\n```',
        inline: false
      },
      {
        name: '\u{1F517} Links',
        value: '[GitHub Release](' + url + ') \u2022 [crates.io](https://crates.io/crates/lean-ctx) \u2022 [npm](https://www.npmjs.com/package/lean-ctx-bin) \u2022 [Website](https://leanctx.com)',
        inline: false
      }
    ],
    footer: {
      text: 'lean-ctx ' + tag + ' \u2022 by ' + author
    },
    timestamp: publishedAt
  }]
};

const siteUrl = 'https://leanctx.com';

const lines = (release.body || '').split('\n').filter(l => l.trim() && !l.startsWith('#') && !l.startsWith('---') && !l.startsWith('```'));
let highlight = '';
if (lines.length > 0) {
  highlight = lines[0].replace(/^[\s*\-]+/, '').replace(/\*\*/g, '').trim();
  if (highlight.length > 60) highlight = highlight.substring(0, 57) + '...';
}

const MAX = 200;
const base = '\u{1F680} lean-ctx ' + tag + ' released!';
const link = '\n\n' + siteUrl;
const tags = '\n\n#AI #DevTools #MCP #OpenSource';
const desc = highlight ? '\n' + highlight : '';

let tweet = base + desc + link + tags;
if (tweet.length > MAX) tweet = base + desc + link;
if (tweet.length > MAX) tweet = base + link + tags;
if (tweet.length > MAX) tweet = base + link;
if (tweet.length > MAX) tweet = '\u{1F680} lean-ctx ' + tag + link;

return [{
  json: {
    discordPayload,
    tweet,
    tag,
    title,
    url: siteUrl
  }
}];

const crypto = require('crypto');
const https = require('https');

const CK = 'wZN4Nch9rHmtHC6Y33lrhe2b5';
const CS = 'm7UuVQAnZdd7H3a5Meoj3pdBNPdduRWnyWnwkHAcgkML8bq6DR';
const AT = '1999852637383217152-kwKk9mneIi0Cb48mQDkV58FRfmQujD';
const AS = '8RHZbwerv7BmQNFOTY8xNkwEpSlbwN0hjTHohgSp7puHN';

const tweet = $input.first().json.tweet;
const url = 'https://api.twitter.com/2/tweets';

function pctEnc(s) {
  return encodeURIComponent(s).replace(/[!'()*]/g, c => '%' + c.charCodeAt(0).toString(16).toUpperCase());
}

const ts = Math.floor(Date.now() / 1000).toString();
const nonce = crypto.randomBytes(16).toString('hex');

const op = {
  oauth_consumer_key: CK,
  oauth_nonce: nonce,
  oauth_signature_method: 'HMAC-SHA1',
  oauth_timestamp: ts,
  oauth_token: AT,
  oauth_version: '1.0'
};

const sp = Object.keys(op).sort().map(k => pctEnc(k) + '=' + pctEnc(op[k])).join('&');
const bs = 'POST&' + pctEnc(url) + '&' + pctEnc(sp);
const sk = pctEnc(CS) + '&' + pctEnc(AS);
const sig = crypto.createHmac('sha1', sk).update(bs).digest('base64');

const ah = 'OAuth ' + Object.entries({...op, oauth_signature: sig}).map(([k,v]) => k + '="' + pctEnc(v) + '"').join(', ');

const body = JSON.stringify({ text: tweet });

const result = await new Promise((resolve) => {
  const req = https.request(url, {
    method: 'POST',
    headers: {
      'Authorization': ah,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body)
    }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
      catch(e) { resolve({ status: res.statusCode, body: data }); }
    });
  });
  req.on('error', err => resolve({ status: 0, error: err.message }));
  req.write(body);
  req.end();
});

return [{ json: { twitter: result, tweet } }];
